def validate_page_pattern(page_type: str, sections: list) -> dict:
    """Validate sections match page archetype."""
    patterns = {
        "saas": ["hero", "social_proof", "how_it_works", "features", "pricing", "cta"],
        "vsl": ["hero", "benefits", "pain", "origin", "mechanism", "testimonials", "offer", "cta"],
        "longform": ["hero", "pain", "agitation", "solution", "proof", "offer", "guarantee", "cta"],
        "advertorial": ["header", "hook", "problem", "discovery", "list", "product", "proof", "cta"]
    }

    required = patterns.get(page_type.lower(), [])
    section_names = [s.get("name", "").lower() for s in sections]

    found = []
    missing = []
    for req in required:
        if any(req in name for name in section_names):
            found.append(req)
        else:
            missing.append(req)

    coverage = len(found) / len(required) if required else 0

    return {
        "passed": coverage >= 0.8,
        "coverage": round(coverage * 100),
        "found": found,
        "missing": missing,
        "page_type": page_type
    }


def validate_video_placement(videos: list) -> dict:
    """Validate video placement strategy."""
    issues = []

    if len(videos) > 3:
        issues.append("More than 3 videos may overwhelm the page")

    # Check first video is above fold
    if videos and videos[0].get("section") != "hero":
        issues.append("Primary video should be in hero section")

    # Check spacing
    sections_used = [v.get("section") for v in videos]
    if len(sections_used) != len(set(sections_used)):
        issues.append("Multiple videos in same section - consider spacing")

    return {
        "passed": len(issues) == 0,
        "video_count": len(videos),
        "issues": issues
    }


def validate_testimonial_distribution(long_testimonials: list, short_testimonials: list) -> dict:
    """Validate testimonial distribution."""
    issues = []

    long_count = len(long_testimonials)
    short_count = len(short_testimonials)

    if long_count < 3:
        issues.append(f"Only {long_count} long testimonials - recommend 3-5")
    if long_count > 5:
        issues.append(f"{long_count} long testimonials - consider converting some to short")

    if short_count < 8:
        issues.append(f"Only {short_count} short testimonials - recommend 8+")

    # Check long testimonials are spaced
    long_sections = [t.get("after_section") for t in long_testimonials]

    return {
        "passed": len(issues) == 0,
        "long_count": long_count,
        "short_count": short_count,
        "issues": issues,
        "recommendations": {
            "long": "3-5 after major persuasive beats",
            "short": "8+ in grid near FAQs and final CTA"
        }
    }


def check_cta_distribution(sections: list) -> dict:
    """Validate CTA placement across page."""
    cta_positions = []
    total = len(sections)

    for i, section in enumerate(sections):
        if section.get("has_cta"):
            cta_positions.append(i)

    # Check distribution
    has_hero_cta = 0 in cta_positions
    has_mid_cta = any(total * 0.4 <= p <= total * 0.7 for p in cta_positions)
    has_final_cta = any(p >= total * 0.8 for p in cta_positions)

    issues = []
    if not has_hero_cta:
        issues.append("No CTA in hero section")
    if not has_final_cta:
        issues.append("No CTA in final sections")

    return {
        "passed": has_hero_cta and has_final_cta,
        "cta_count": len(cta_positions),
        "distribution": {
            "hero": has_hero_cta,
            "mid_page": has_mid_cta,
            "final": has_final_cta
        },
        "issues": issues
    }
